#include <stdio.h>
#include <stdint.h>
const long long MOD = 1000000007LL;
long long modpow(long long a, long long e) {
    long long r = 1 % MOD;
    a %= MOD;
    while (e) {
        if (e & 1) r = r * a % MOD;
        a = a * a % MOD;
        e >>= 1;
    }
    return r;
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, M; scanf("%lld %lld", &N, &M);
        long long p1 = modpow(M, N);
        long long p2 = (M==0)?0:modpow(M-1, N);
        long long ans = (M % MOD) * ((p1 - p2 + MOD) % MOD) % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

