let out = [];
for (let t = 0; t < T; ++t) {
  const N = BigInt(input[idx++]);
  const M = BigInt(input[idx++]);
  const p1 = modPow(M, N);
  const p2 = M === 0n ? 0n : modPow(M - 1n, N);
  const ans = (M % MOD) * ((p1 - p2 + MOD) % MOD) % MOD;
  out.push(ans.toString());
